#include <bits/stdc++.h>
using namespace std;

const int N=2e5+10,L=5e6+10;

inline void rd(string &s){
    char ch=getchar();
    s="";
    while(ch<'a' || 'z'<ch) ch=getchar();
    while('a'<=ch && ch<='z') s+=ch,ch=getchar();
}

struct Node{
    int son[27],fail;
}tr[L];

int n,q,tot=1,sum[L],qu[L];
string s[2],t[2],sp;
vector<int> e[L];

inline void calc(string &a,string &b){
    int l=-1,r=a.size()-1;
    for(int i=0;i<a.size();i++)
        if(a[i]!=b[i]){
            r=i;
            if(l==-1)
                l=i;
        }
    l=max(l,0);
    sp="";
    for(int i=0;i<a.size();i++){
        if(l==i)
            sp+='{';
        sp+=a[i];
        sp+=b[i];
        if(r==i)
            sp+='{';
    }
    // 'z'+1='{'
}

void Insert(string &s){
    int p=1;
    for(int i=0;i<s.size();i++){
        if(!tr[p].son[s[i]-'a'])
            tr[p].son[s[i]-'a']=++tot;
        p=tr[p].son[s[i]-'a'];
    }
    sum[p]++;
}

void dfs(int x){
    for(int y:e[x]){
        sum[y]+=sum[x];
        dfs(y);
    }
}

void build(){
    int hh=1,tt=0;
    tr[1].fail=1;
    for(int i=0;i<27;i++)
        if(tr[1].son[i]){
            tr[tr[1].son[i]].fail=1;
            qu[++tt]=tr[1].son[i];
        }else
            tr[1].son[i]=1;
    while(hh<=tt){
        int x=qu[hh++];
        e[tr[x].fail].push_back(x);
        for(int i=0;i<27;i++)
            if(tr[x].son[i]){
                tr[tr[x].son[i]].fail=tr[tr[x].fail].son[i];
                qu[++tt]=tr[x].son[i];
            }else
                tr[x].son[i]=tr[tr[x].fail].son[i];
    }
    dfs(1);
}

int Query(string &s){
    int p=1,res=0;
    for(int i=0;i<s.size();i++){
        p=tr[p].son[s[i]-'a'];
        res+=sum[p];
    }
    return res;
}

int main(){
    scanf("%d%d",&n,&q);
    for(int i=1;i<=n;i++){
        rd(s[0]),rd(s[1]);
        calc(s[0],s[1]);
        Insert(sp);
    }
    build();
    while(q--){
        rd(t[0]),rd(t[1]);
        calc(t[0],t[1]);
        printf("%d\n",Query(sp));
    }
    return 0;
}
